260	  private applyLicensingViewListFromApi(views: any[], def: { view_name: string } | null): void {
261	    if (views && views.length) {
262	      this.viewLayouts = views.map((v: any) => ({
263	        layout_name: v.view_name,
264	        is_default: !!v.is_default
265	      }));
266	    } else {
267	      this.viewLayouts = [{ layout_name: 'Default' }];
268	    }
269	    const defaultName = def?.view_name;
270	    const match = defaultName && this.viewLayouts.find((v) => v.layout_name === defaultName);
271	    this.selectedViewLayout = match || this.viewLayouts[0];
272	  }
273	
274	  compareViewLayouts = (a: { layout_name: string } | null, b: { layout_name: string } | null): boolean =>
275	    a?.layout_name != null && b?.layout_name != null && a.layout_name === b.layout_name;
276	
277	  async onSaveNewView(value) {
278	    if (!value || !value.trim()) return;
279	    
280	    const viewName = value.trim();
281	    this.viewLayouts.push({ layout_name: viewName, is_default: false });
282	    this.selectedViewLayout = { layout_name: viewName, is_default: false };
283	    
284	    const columnState = this.gridApi.getColumnState();
285	    const filterModel = this.gridApi.getFilterModel();
286	
287	    this.itemService.saveGridViewState({
288	      grid_id: 'licensingTracking',
289	      view_name: viewName,
290	      column_state: columnState,
291	      filter_model: filterModel
292	    }).subscribe(
293	      (data) => {
294	        this._snakcbar.open(`View "${viewName}" was created successfully.`, 'close');
295	      },
296	      (error) => {
297	        this._snakcbar.open(`Failed to save view. Please try again.`, 'close');
298	        console.error('Error saving grid view state:', error);
299	      }
300	    );
301	  }
302	
303	  onViewChange(value) {
304	    this.selectedViewLayout = value;
305	    this.applyLicensingGridViewStateForViewName(value.layout_name);
306	  }
