308	  private applyLicensingGridViewStateForViewName(layoutName: string): void {
309	    if (!this.gridApi || !layoutName) {
310	      return;
311	    }
312	    this.itemService.getGridViewState({ grid_id: 'licensingTracking', view_name: layoutName }).subscribe((res: any) => {
313	      if (res) {
314	        if (res.column_state && res.column_state.length > 0) {
315	          this.gridApi.applyColumnState({ state: res.column_state, applyOrder: true });
316	        }
317	        if (res.filter_model) {
318	          setTimeout(() => {
319	            this.gridApi.setFilterModel(res.filter_model);
320	          }, 200);
321	        }
322	      } else {
323	        this.itemService
324	          .getSelectedGridView({ layout_name: layoutName, grid_id: 'licensing_tracking' })
325	          .subscribe(async (legacyRes: any) => {
326	            if (legacyRes.length > 0) {
327	              this.gridApi.applyColumnState({ state: legacyRes, applyOrder: true });
328	            }
329	          });
330	      }
331	    });
332	  }
