350	          this.viewLayouts.find((x) => x.layout_name === v.layout_name) ?? this.selectedViewLayout;
351	        this._snakcbar.open('This view will load by default when you open Licensing Tracking.', 'close');
352	      },
353	      error: (err) => {
354	        this._snakcbar.open(err?.error?.message || 'Could not set default view.', 'close');
355	      }
356	    });
357	  }
