393	        }
394	      );
395	    } else {
396	      this._snakcbar.open(`You can't save on Default view. Please select a different view or create a new one.`, 'close')
397	    }
398	  }
399	
400	  compareFeedbacks = (oldFeedback, newfeedback) => {
401	    for (let i = 0; i < oldFeedback.length; i++) {
402	      if (oldFeedback[i]?.status.toLowerCase() === newfeedback?.status.toLowerCase() && oldFeedback[i]?.from?.toLowerCase() === newfeedback?.from?.toLowerCase() && oldFeedback[i]?.package === newfeedback?.package) {
403	        newfeedback.id = oldFeedback[i].id
404	      }
405	    }
406	  }
407	
408	  openBulkDialog(phase) {
409	    // Get the selected 'package' and 'from' context menu options
410	    const type = document.getElementsByClassName('ag-menu-option-active')[1]?.textContent;
411	    const from = document.getElementsByClassName('ag-menu-option-active')[3]?.textContent;
412	
413	    const dialogRef = this.dialog.open(BulkUpdateComponent, {
414	      disableClose: true,
415	      width: '700px',
416	      data: { from: from, package: type, phase: phase.phase, status: phase.status }
417	    });
418	
419	    dialogRef.afterClosed().subscribe(async (data) => {
420	      if (data) {
421	        const rows = this.params.api.getSelectedRows();
422	        const mergedData = [];
423	        const ids = [];
424	
425	        rows.forEach((row) => {
426	          ids.push(row.id.toString());
427	        });
428	
429	        let newData = JSON.parse(JSON.stringify(data));
430	        const licenses = await <any>this.itemDetailService.BulkGetLicensingStatus(ids).pipe(first()).toPromise();
431	
432	        rows.forEach((row) => {
433	          if (licenses && licenses[row.id.toString()]) {
434	            const oldFeedback = licenses[row.id.toString()];
435	            // Add id field and update existing feedback if it already exists
436	            this.compareFeedbacks(oldFeedback, newData);
437	          }
438	
439	          newData.itemheader_id_fk = row.id.toString();
440	          if(newData.from.toLowerCase() === 'licensor') newData.from = row['Licensor Code'] 
441	          mergedData.push(JSON.parse(JSON.stringify(newData)));
442	        });
443	
444	        this.itemDetailService.BulkAddLicensingStatus(mergedData).subscribe({
445	          next: (res: any) => {
446	            console.log('BulkAddLicensingStatus response:', res);
447	            if (res && res.statusCode === 200) {
448	              this._snackBar.open(`Successfully bulk updated licenses!`, 'close');
449	              // Reload the datasource
450	              if (window['reloadLicensingDatasource']) {
451	                window['reloadLicensingDatasource']();
452	              }
453	            } else {
454	              this._snackBar.open(`An error occurred while updating licenses`, 'close');
455	            }
456	          },
457	          error: (err: any) => {
458	            console.error('BulkAddLicensingStatus error:', err);
459	            this._snackBar.open(`An error occurred while updating licenses: ${err.message || 'Unknown error'}`, 'close');
460	          },
461	          complete: () => {
462	            console.log('BulkAddLicensingStatus completed');
463	          }
464	        });
465	      }
466	    });
467	  }
468	
469	  private decrementLoaderIfInitialLoad(): void {
470	    if (this.isInitialLoad) {
471	      this.isInitialLoad = false;
472	      this.loaderService.decrement();
473	    }
474	  }
