476	  async ngOnInit() {
477	    // Start loader immediately to prevent blank page flash
478	    this.loaderService.increment();
479	    
480	    setTimeout(() => this.gridApi?.setGridOption("loading", true), 100)
481	
482	    try {
483	      const res: any = await this.itemService.verifyRole().toPromise();
484	      this.role = res.role
485	      window['role'] = this.role
486	      this.access = res.access
487	      if (this.role == 'vendor') {
488	        this.detailRowHeight = 200
489	      }
490	    } catch (err) {
491	      console.error('[LicensingTracking] verifyRole failed:', err);
492	    }
493	
494	    // Collect all phases and bind action for context menu phases
495	    this.itemDetailService.getLicenseFeedBacks({ from: 'POP' }).subscribe(data => {
496	      if (Array.isArray(data)) {
497	        let res = [];
498	        data.forEach(phase => {
499	          res.push({
500	            name: phase.phase + ' | ' + phase.status,
501	            action: () => this.openBulkDialog(phase)
502	          });
503	        });
504	        if (!window['phases']) {
505	          window['phases'] = { pop: null, licensor: null };
506	        }
507	        window['phases'].pop = res;
508	      }
509	    });
510	
511	    this.itemDetailService.getLicenseFeedBacks({ from: 'Licensor' }).subscribe(data => {
512	      let res = []
513	      if (Array.isArray(data)) {
514	        data.forEach((phase) => res.push({
515	          name: phase.phase + ' | ' + phase.status,
516	          action: () => this.openBulkDialog(phase)
517	        }))
518	        if (!window['phases']) {
519	          window['phases'] = { pop: null, licensor: null };
520	        }
521	        window['phases'].licensor = res;
522	      }
523	    })
524	
525	    try {
526	      const data: any = await this.itemService.getCompanyCode().toPromise();
527	      this.selectedCompanyCode = data[0]['company_name']
528	      this.companyCode = data;
529	      this.selectedDivisionCode = data[0].divisionCodes
530	      window['selectedDivisionCode'] = this.selectedDivisionCode;
531	      this.divisionCode = data[0].divisionCodes;
532	
533	      try {
534	        const res: any = await this.itemService.getRFQItemStatus().toPromise();
535	        if (this.role != 'vendor') {
536	          this.selectedDivisionCodeStatus.push(res[0])
537	        } else {
538	          this.selectedDivisionCodeStatus = res
539	        }
540	        window['selectedDivisionCodeStatus'] = this.selectedDivisionCodeStatus;
541	        res.forEach(async (element) => {
542	          this.divisionCodeStatus.push(element)
543	          return this.divisionCodeStatus
544	        });
545	
546	        if (this.selectedDivisionCode && this.selectedDivisionCodeStatus) {
547	
548	          // await the view layout
549	        //  const columnHeaders: any = await this.trackingService.getViewlayout('licensing_tracking').toPromise();
550	
551	          const columnHeaders = [...LICENSING_TRACKING_COLUMN_HEADERS_CONFIG.columnDefs];
552	
553	          let licenseStatuses: string[] = [];
554	          try {
555	            const statuses: any = await firstValueFrom(this.trackingService.getLicenseStatuses());
556	            licenseStatuses = Array.isArray(statuses) ? statuses.filter((v) => !!v) : [];
557	          } catch (err) {
558	            console.error('[LicensingTracking] getLicenseStatuses failed:', err);
559	          }
