1089	  private getDateValueGetter(fieldName: string): (params: any) => Date | null {
1090	    return (params: any) => {
1091	      if (!params.data) return null;
1092	      const dateValue = params.data[fieldName];
1093	      if (!dateValue) return null;
1094	      
1095	      // Convert to Date object if it's a string
1096	      if (typeof dateValue === 'string') {
1097	        const date = new Date(dateValue);
1098	        return isNaN(date.getTime()) ? null : date;
1099	      }
1100	      
1101	      // If already a Date object, return it
1102	      if (dateValue instanceof Date) {
1103	        return dateValue;
1104	      }
1105	      
1106	      // Try to convert to Date
1107	      const date = new Date(dateValue);
1108	      return isNaN(date.getTime()) ? null : date;
1109	    };
