1112	  /**
1113	   * Returns a comparator function for date filters that compares dates at midnight
1114	   */
1115	  private getDateComparator(): (filterLocalDateAtMidnight: Date, cellValue: any) => number {
1116	    return (filterLocalDateAtMidnight: Date, cellValue: any) => {
1117	      if (!cellValue) return -1;
1118	      
1119	      const cellDate = cellValue instanceof Date 
1120	        ? cellValue 
1121	        : new Date(cellValue);
1122	      
1123	      if (isNaN(cellDate.getTime())) return -1;
1124	      
1125	      // Reset time to midnight for comparison
1126	      const cellDateAtMidnight = new Date(
1127	        cellDate.getFullYear(),
1128	        cellDate.getMonth(),
1129	        cellDate.getDate()
1130	      );
1131	      
1132	      const filterDateAtMidnight = new Date(
1133	        filterLocalDateAtMidnight.getFullYear(),
1134	        filterLocalDateAtMidnight.getMonth(),
1135	        filterLocalDateAtMidnight.getDate()
1136	      );
1137	      
1138	      if (cellDateAtMidnight.getTime() === filterDateAtMidnight.getTime()) {
1139	        return 0;
1140	      }
1141	      if (cellDateAtMidnight < filterDateAtMidnight) {
1142	        return -1;
1143	      }
1144	      return 1;
1145	    };
1146	  }
