1148	  dateComparator(date1, date2, nodeA, nodeB, isInverted) {
1149	    function formatDate(input) {
1150	      if (input == null) return ''
1151	      if (input.includes("-")) {
1152	        var datePart = input.match(/\d+/g),
1153	          year = datePart[0].substring(), // get only two digits
1154	          month = datePart[1], day = datePart[2];
1155	        return month + '/' + day + '/' + year;
1156	      } else {
1157	        return input
1158	      }
1159	    }
1160	
1161	    function monthToComparableNumber(date) {
1162	
1163	      if (date === undefined || date === null || date.length !== 10) {
1164	        return date.length;
1165	      }
1166	      var yearNumber = date.substring(6, 10);
1167	      var dayNumber = date.substring(3, 5);
1168	      var monthNumber = date.substring(0, 2);
1169	      var result = yearNumber * 10000 + monthNumber * 100 + dayNumber;
1170	      return result;
1171	    }
1172	
1173	
1174	    date1 = formatDate(date1)
1175	
1176	    date2 = formatDate(date2)
1177	
1178	    var date1Number = monthToComparableNumber(date1);
1179	    var date2Number = monthToComparableNumber(date2);
1180	    if (date1Number === null && date2Number === null) {
1181	      return 0;
1182	    }
1183	    if (date1Number === null) {
1184	      return -1;
1185	    }
1186	    if (date2Number === null) {
1187	      return 1;
1188	    }
1189	    return date1Number - date2Number;
1190	  }
