424	LicTracking.addLicenseImage = async (req, result) => {
425	  try {
426	    const user = await getUserInfo(req.headers.authorization);
427	    const item_num_id_fk = Number(req.body.itemheader_id_fk);
428	    const image_link = req.body.image_link || req.body.sharedLink || req.body.imageUrl || req.body.url;
429	    const thumb_link = req.body.thumb_link || req.body.thumbSharedLink || req.body.thumbnailUrl || req.body.thumbnail;
430	
431	    if (!item_num_id_fk || !image_link || !thumb_link) {
432	      return result({ message: 'itemheader_id_fk, image_link and thumb_link are required' });
433	    }
434	
435	    const [itemHeader] = await Promise.all([
436	      sql.itemAttachment.findOne({
437	        where: { item_num_id_fk },
438	        order: [['item_attachment_id', 'ASC']]
439	      }),
440	      sql.itemHeader.findByPk(item_num_id_fk, { attributes: ['compan_code_fk', 'div_code_fk'] })
441	    ]);
442	
443	    const created_user = req.body.created_user || user?.name || null;
444	    const created_time = req.body.created_time ? new Date(req.body.created_time).getTime() : Date.now();
445	    const companyCode_name = itemHeader?.compan_code_fk || 'EDGEHOME';
446	    const divisionCode_name = itemHeader?.div_code_fk;
447	    const uuid = uuidv4();
448	
449	    const buildAttachmentPayload = (link, displayName) => {
450	      if (!link) return null;
451	      const fileName = (link.split('/').pop() || '').split('?')[0];
452	      const extension = (fileName.split('.').pop() || '').toLowerCase() || 'jpeg';
453	      const attachment_type = displayName === 'Thumb' ? `image/${extension}` : extension;
454	
455	      return {
456	        attachment_type,
457	        attachment_display_name: displayName,
458	        attachment_link: link,
459	        item_num_id_fk,
460	        item_attachment_createdTime: created_time,
461	        item_attachment_createdUser: created_user,
462	        item_attachment_modTime: created_time,
463	        item_attachment_modUser: created_user,
464	        item_attachment_fileName: fileName,
465	        companyCode_name,
466	        divisionCode_name,
467	        item_attachment_colorCode: '',
468	        item_attachment_resourceId: 1,
469	        primary_image: false,
470	        uuid
471	      };
472	    };
473	
474	    const attachments = [
475	      buildAttachmentPayload(image_link, 'Image'),
476	      buildAttachmentPayload(thumb_link, 'Thumb')
477	    ].filter(Boolean);
478	
479	    const createdRows = [];
480	    for (const attachment of attachments) {
481	      const [row] = await sql.itemAttachment.findOrCreate({
482	        where: {
483	          item_num_id_fk: attachment.item_num_id_fk,
484	          attachment_display_name: attachment.attachment_display_name,
485	          attachment_link: attachment.attachment_link,
486	        },
487	        defaults: attachment
488	      });
489	      createdRows.push(row.get({ plain: true }));
490	    }
491	
492	    return result(null, createdRows);
493	  } catch (err) {
494	    console.error('addLicenseImage error', err);
495	    return result(err);
496	  }
497	}
