380	  async uploadPendingAttachments(): Promise<AttachmentPayload[]> {
381	    const uploads: AttachmentPayload[] = [];
382	
383	    for (const attachment of this.attachments) {
384	      if (attachment.link) {
385	        uploads.push({
386	          name: attachment.name,
387	          link: attachment.link,
388	          type: attachment.type,
389	          size: attachment.size
390	        });
391	        continue;
392	      }
393	
394	      attachment.status = 'uploading';
395	      const storageName = this.buildStorageFileName(attachment.file);
396	      const contentType = attachment.type || 'application/octet-stream';
397	      await this.helper.saveToDigitalOceanAndDB(storageName, contentType, attachment.file);
398	      const link = this.helper.buildPublicUrl(storageName);
399	      attachment.link = link;
400	      attachment.status = 'uploaded';
401	      uploads.push({
402	        name: attachment.name,
403	        link,
404	        type: attachment.type,
405	        size: attachment.size
406	      });
407	    }
408	
409	    return uploads;
410	  }
