444	  formatBytes(bytes: number): string {
445	    if (!bytes) {
446	      return '0 B';
447	    }
448	    const units = ['B', 'KB', 'MB', 'GB'];
449	    const exponent = Math.min(Math.floor(Math.log(bytes) / Math.log(1024)), units.length - 1);
450	    const value = bytes / Math.pow(1024, exponent);
451	    return `${value.toFixed(1)} ${units[exponent]}`;
452	  }
